    , #{survey2Cd, jdbcType=VARCHAR}
    , #{survey2Text, jdbcType=VARCHAR}
    , #{surveyScore, jdbcType=VARCHAR}
    , #{surveySuggestion, jdbcType=VARCHAR}
    , #{memo, jdbcType=VARCHAR}
