    , #{regstId, jdbcType=VARCHAR}
    , CAST(TO_TIMESTAMP(#{regstDttm, jdbcType=VARCHAR}, 'YYYY-MM-DD HH24:MI:SS.FF6') AS DATE)
    , #{procCd, jdbcType=VARCHAR}
    , #{scanId, jdbcType=VARCHAR}
